// src/platform/macos.rs
use super::*;
use std::process::Command;

pub struct MacOS;

impl MacOS {
    pub fn new() -> Self {
        Self
    }
}

impl Platform for MacOS {
    fn get_volume(&self) -> PlatformResult<i32> {
        let output = Command::new("osascript")
            .args(["-e", "output volume of (get volume settings)"])
            .output()
            .map_err(|e| PlatformError::OperationFailed(e.to_string()))?;

        if !output.status.success() {
            return Err(PlatformError::AudioUnavailable(
                String::from_utf8_lossy(&output.stderr).to_string()
            ));
        }

        String::from_utf8_lossy(&output.stdout)
            .trim()
            .parse()
            .map_err(|_| PlatformError::OperationFailed("Failed to parse volume".into()))
    }

    fn set_volume(&self, vol: i32) -> PlatformResult<()> {
        let vol = vol.clamp(0, 100);
        let output = Command::new("osascript")
            .args(["-e", &format!("set volume output volume {}", vol)])
            .output()
            .map_err(|e| PlatformError::OperationFailed(e.to_string()))?;

        if output.status.success() {
            Ok(())
        } else {
            Err(PlatformError::OperationFailed(
                String::from_utf8_lossy(&output.stderr).to_string()
            ))
        }
    }

    fn is_muted(&self) -> PlatformResult<bool> {
        let output = Command::new("osascript")
            .args(["-e", "output muted of (get volume settings)"])
            .output()
            .map_err(|e| PlatformError::OperationFailed(e.to_string()))?;

        let result = String::from_utf8_lossy(&output.stdout).trim().to_lowercase();
        Ok(result == "true")
    }

    fn toggle_mute(&self) -> PlatformResult<()> {
        Command::new("osascript")
            .args(["-e", "set volume output muted not (output muted of (get volume settings))"])
            .output()
            .map_err(|e| PlatformError::OperationFailed(e.to_string()))?;
        Ok(())
    }

    fn get_mic_volume(&self) -> PlatformResult<i32> {
        let output = Command::new("osascript")
            .args(["-e", "input volume of (get volume settings)"])
            .output()
            .map_err(|e| PlatformError::OperationFailed(e.to_string()))?;

        String::from_utf8_lossy(&output.stdout)
            .trim()
            .parse()
            .map_err(|_| PlatformError::OperationFailed("Failed to parse mic volume".into()))
    }

    fn set_mic_volume(&self, vol: i32) -> PlatformResult<()> {
        let vol = vol.clamp(0, 100);
        Command::new("osascript")
            .args(["-e", &format!("set volume input volume {}", vol)])
            .output()
            .map_err(|e| PlatformError::OperationFailed(e.to_string()))?;
        Ok(())
    }

    fn is_mic_muted(&self) -> PlatformResult<bool> {
        // macOS doesn't have direct mic mute, check if volume is 0
        Ok(self.get_mic_volume()? == 0)
    }

    fn toggle_mic_mute(&self) -> PlatformResult<()> {
        let current = self.get_mic_volume()?;
        if current > 0 {
            self.set_mic_volume(0)
        } else {
            self.set_mic_volume(50) // Restore to 50%
        }
    }

    fn send_key_down(&self, key: Key) -> PlatformResult<()> {
        let keycode = match key {
            Key::F15 => 113,
            Key::F16 => 106,
            Key::F17 => 64,
            Key::F18 => 79,
            Key::F19 => 80,
        };
        let script = format!(r#"tell application "System Events" to key down {}"#, keycode);
        Command::new("osascript")
            .args(["-e", &script])
            .output()
            .map_err(|e| PlatformError::OperationFailed(e.to_string()))?;
        Ok(())
    }

    fn send_key_up(&self, key: Key) -> PlatformResult<()> {
        let keycode = match key {
            Key::F15 => 113,
            Key::F16 => 106,
            Key::F17 => 64,
            Key::F18 => 79,
            Key::F19 => 80,
        };
        let script = format!(r#"tell application "System Events" to key up {}"#, keycode);
        Command::new("osascript")
            .args(["-e", &script])
            .output()
            .map_err(|e| PlatformError::OperationFailed(e.to_string()))?;
        Ok(())
    }

    fn send_media_key(&self, key: MediaKey) -> PlatformResult<()> {
        // Use NX key codes for media keys
        let (keycode, keydown, keyup) = match key {
            MediaKey::PlayPause => (16, 0xa00, 0xb00),
            MediaKey::NextTrack => (17, 0xa00, 0xb00),
            MediaKey::PrevTrack => (18, 0xa00, 0xb00),
            MediaKey::Mute => (7, 0xa00, 0xb00),
            MediaKey::VolumeUp => (0, 0xa00, 0xb00),
            MediaKey::VolumeDown => (1, 0xa00, 0xb00),
        };

        // Use CGEventCreateKeyboardEvent or osascript
        let script = format!(
            r#"
            do shell script "osascript -e 'tell application \"System Events\" to key code {}'"
            "#,
            keycode
        );
        Command::new("osascript")
            .args(["-e", &script])
            .output()
            .map_err(|e| PlatformError::OperationFailed(e.to_string()))?;
        Ok(())
    }

    fn list_output_devices(&self) -> PlatformResult<Vec<AudioDevice>> {
        // Use system_profiler or CoreAudio
        let output = Command::new("system_profiler")
            .args(["SPAudioDataType", "-json"])
            .output()
            .map_err(|e| PlatformError::OperationFailed(e.to_string()))?;

        // Parse JSON output and extract devices
        // For full implementation, use coreaudio-rs crate
        todo!("Parse audio devices from system_profiler JSON")
    }

    fn get_default_output(&self) -> PlatformResult<AudioDevice> {
        // Use CoreAudio to get default device
        todo!("Implement with coreaudio-rs")
    }

    fn set_default_output(&self, device_id: &str) -> PlatformResult<()> {
        // Use CoreAudio to set default device
        todo!("Implement with coreaudio-rs")
    }

    fn list_input_devices(&self) -> PlatformResult<Vec<AudioDevice>> {
        todo!("Implement with coreaudio-rs")
    }

    fn send_notification(&self, title: &str, body: &str, _urgency: Urgency) -> PlatformResult<()> {
        let script = format!(
            r#"display notification "{}" with title "{}""#,
            body.replace('"', r#"\""#),
            title.replace('"', r#"\""#)
        );
        Command::new("osascript")
            .args(["-e", &script])
            .output()
            .map_err(|e| PlatformError::OperationFailed(e.to_string()))?;
        Ok(())
    }

    fn get_foreground_app(&self) -> PlatformResult<Option<AppInfo>> {
        let output = Command::new("osascript")
            .args(["-e", r#"
                tell application "System Events"
                    set frontApp to first application process whose frontmost is true
                    return {name of frontApp, bundle identifier of frontApp}
                end tell
            "#])
            .output()
            .map_err(|e| PlatformError::OperationFailed(e.to_string()))?;

        let result = String::from_utf8_lossy(&output.stdout).trim().to_string();
        let parts: Vec<&str> = result.split(", ").collect();

        if parts.len() >= 2 {
            Ok(Some(AppInfo {
                name: parts[0].to_string(),
                bundle_id: Some(parts[1].to_string()),
                process_id: None,
                executable: None,
            }))
        } else {
            Ok(None)
        }
    }
}
