```rust
use crate::platform::{CurrentPlatform, Platform};

fn handle_rotation(platform: &CurrentPlatform, direction: i8, step: i32) {
    match platform.get_volume() {
        Ok(current) => {
            let new_vol = (current + direction as i32 * step).clamp(0, 100);
            if let Err(e) = platform.set_volume(new_vol) {
                log::error!("Failed to set volume: {}", e);
            }
        }
        Err(e) => log::error!("Failed to get volume: {}", e),
    }
}
