// src/cli/help.rs
use colored::*;
use crate::config::Config;

pub struct QuickstartOptions {
    pub color: bool,
    pub emoji: bool,
    pub show_status: bool,
}

impl Default for QuickstartOptions {
    fn default() -> Self {
        Self {
            color: atty::is(atty::Stream::Stdout),
            emoji: true,
            show_status: true,
        }
    }
}

pub fn print_quickstart(opts: QuickstartOptions) {
    let config = Config::load();

    // Header
    if opts.color {
        println!("{}", "╔══════════════════════════════════════════════════════════════╗".cyan());
        let emoji = if opts.emoji { "🎛️  " } else { "" };
        println!("{}  {}Surface Dial Volume Controller  {}{}",
            "║".cyan(),
            emoji,
            env!("CARGO_PKG_VERSION").bold(),
            "║".cyan());
        println!("{}", "╚══════════════════════════════════════════════════════════════╝".cyan());
    } else {
        println!("Surface Dial Volume Controller v{}\n", env!("CARGO_PKG_VERSION"));
    }
    println!();

    // Live status section
    if opts.show_status {
        print_status_section(&config, &opts);
    }

    // Controls section
    print_controls_section(&opts);

    // Features section
    print_features_section(&config, &opts);

    // Commands section
    print_commands_section(&opts);

    // Quick config examples
    print_config_examples(&opts);
}

