#[cfg(test)]
mod tests {
    use super::*;
    use std::sync::atomic::{AtomicI32, AtomicBool, Ordering};

    // Thread-safe mock platform for testing
    pub struct MockPlatform {
        volume: AtomicI32,
        mic_volume: AtomicI32,
        muted: AtomicBool,
        mic_muted: AtomicBool,
        error_on_next: AtomicBool,
    }

    impl Default for MockPlatform {
        fn default() -> Self {
            Self {
                volume: AtomicI32::new(50),
                mic_volume: AtomicI32::new(50),
                muted: AtomicBool::new(false),
                mic_muted: AtomicBool::new(false),
                error_on_next: AtomicBool::new(false),
            }
        }
    }

    impl MockPlatform {
        pub fn simulate_error_on_next(&self) {
            self.error_on_next.store(true, Ordering::SeqCst);
        }
    }

    impl Platform for MockPlatform {
        fn get_volume(&self) -> PlatformResult<i32> {
            if self.error_on_next.swap(false, Ordering::SeqCst) {
                return Err(PlatformError::AudioUnavailable("Simulated error".into()));
            }
            Ok(self.volume.load(Ordering::SeqCst))
        }

        fn set_volume(&self, vol: i32) -> PlatformResult<()> {
            if self.error_on_next.swap(false, Ordering::SeqCst) {
                return Err(PlatformError::AudioUnavailable("Simulated error".into()));
            }
            self.volume.store(vol.clamp(0, 100), Ordering::SeqCst);
            Ok(())
        }

        fn is_muted(&self) -> PlatformResult<bool> {
            Ok(self.muted.load(Ordering::SeqCst))
        }

        fn toggle_mute(&self) -> PlatformResult<()> {
            let current = self.muted.load(Ordering::SeqCst);
            self.muted.store(!current, Ordering::SeqCst);
            Ok(())
        }

        // ... other methods with similar error simulation
    }

    #[test]
    fn test_volume_clamping_at_boundaries() {
        let p = MockPlatform::default();

        p.set_volume(150).unwrap();
        assert_eq!(p.get_volume().unwrap(), 100, "Volume should clamp to 100");

        p.set_volume(-10).unwrap();
        assert_eq!(p.get_volume().unwrap(), 0, "Volume should clamp to 0");

        p.set_volume(50).unwrap();
        assert_eq!(p.get_volume().unwrap(), 50, "Volume in range should be set exactly");
    }

    #[test]
    fn test_mute_toggle_idempotent() {
        let p = MockPlatform::default();

        assert!(!p.is_muted().unwrap());
        p.toggle_mute().unwrap();
        assert!(p.is_muted().unwrap());
        p.toggle_mute().unwrap();
        assert!(!p.is_muted().unwrap());
    }

    #[test]
    fn test_platform_error_handling() {
        let p = MockPlatform::default();

        // Simulate error
        p.simulate_error_on_next();
        let result = p.get_volume();
        assert!(result.is_err());

        // Next call should succeed
        let result = p.get_volume();
        assert!(result.is_ok());
    }

    #[test]
    fn test_volume_unchanged_when_set_fails() {
        let p = MockPlatform::default();
        p.set_volume(30).unwrap();

        p.simulate_error_on_next();
        let result = p.set_volume(80);
        assert!(result.is_err());

        // Volume should still be 30
        assert_eq!(p.get_volume().unwrap(), 30);
    }
}
