            assert_eq!(curve.apply(100), 100, "{} should map 100 -> 100", curve.name());
            assert_eq!(curve.inverse(0), 0, "{} inverse should map 0 -> 0", curve.name());
            assert_eq!(curve.inverse(100), 100, "{} inverse should map 100 -> 100", curve.name());
        }
