        let curve = LogarithmicCurve::default();

        // At 50% dial position, logarithmic curve should give > 50% volume
        let mid = curve.apply(50);
        assert!(mid > 50, "Logarithmic curve at 50% dial should give > 50% volume, got {}", mid);
        assert!(mid < 80, "Logarithmic curve at 50% dial should give < 80% volume, got {}", mid);

        log::info!("Logarithmic curve: 50% dial -> {}% volume", mid);
    }

