        // Test interpolation
        let mid = curve.apply(25);
        assert!(mid >= 10 && mid <= 15, "Interpolation at 25% should be ~12, got {}", mid);
    }

    #[test]
    fn test_curve_clamping() {
        init_logging();
        let curve = LogarithmicCurve::default();

        // Out of range inputs should be clamped
        assert_eq!(curve.apply(-10), 0);
        assert_eq!(curve.apply(150), 100);
        assert_eq!(curve.inverse(-10), 0);
        assert_eq!(curve.inverse(150), 100);
