        print!("{:3}% │", y_val);

        for x in 0..=20 {
            let x_val = x * 5;
            let actual = curve.apply(x_val);
            if (actual as i32 - y_val as i32).abs() <= 5 {
                print!("●");
            } else if actual > y_val {
