// src/cli/logs.rs

pub fn view_logs(lines: Option<usize>, follow: bool, json: bool) {
    let log_path = dirs::data_local_dir()
        .unwrap_or_default()
        .join("surface-dial")
        .join("daemon.log");

    if !log_path.exists() {
        eprintln!("No log file found at {:?}", log_path);
        return;
    }

    if follow {
        // Tail -f style
        use std::io::{BufRead, BufReader};
        use std::process::Command;

        if cfg!(unix) {
            Command::new("tail")
                .args(["-f", log_path.to_str().unwrap()])
                .spawn()
                .expect("Failed to tail log")
                .wait()
                .ok();
        } else {
            // Windows: use Get-Content -Wait
            Command::new("powershell")
                .args(["-Command", &format!("Get-Content '{}' -Wait", log_path.display())])
                .spawn()
                .expect("Failed to tail log")
                .wait()
                .ok();
        }
    } else {
        // Read last N lines
        let file = std::fs::File::open(&log_path).expect("Failed to open log");
        let reader = std::io::BufReader::new(file);
        let all_lines: Vec<String> = reader.lines().filter_map(|l| l.ok()).collect();

        let n = lines.unwrap_or(50);
        let start = all_lines.len().saturating_sub(n);

        for line in &all_lines[start..] {
            if json {
                println!("{}", line);
            } else {
                // Pretty print
                println!("{}", line);
            }
        }
    }
}

pub fn clear_logs() {
    let log_dir = dirs::data_local_dir()
        .unwrap_or_default()
        .join("surface-dial");

    if log_dir.exists() {
        for entry in std::fs::read_dir(&log_dir).unwrap() {
            if let Ok(entry) = entry {
                let path = entry.path();
                if path.extension().map(|e| e == "log").unwrap_or(false) {
                    std::fs::remove_file(&path).ok();
                    println!("Removed: {:?}", path);
                }
            }
        }
    }
}
