// In src/daemon.rs

impl Daemon {
    fn handle_rotation(&mut self, direction: i8) {
        let old_volume = self.get_current_volume();

        // ... adjust volume ...

        let new_volume = self.get_current_volume();

        // Play appropriate feedback sound
        if let Some(feedback) = &self.audio_feedback {
            if new_volume == 0 || new_volume == 100 {
                feedback.boundary();
            } else if new_volume != old_volume {
                feedback.tick();
            }
            // If volume didn't change (already at boundary), no sound
        }
    }

    fn handle_click(&mut self, click_type: ClickResult) {
        if let Some(feedback) = &self.audio_feedback {
            match click_type {
                ClickResult::SingleClick => feedback.mute_toggle(),
                ClickResult::DoubleClick => feedback.mode_change(),
                _ => {}
            }
        }
    }
}
