// src/audio/devices.rs

use serde::{Deserialize, Serialize};

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct AudioDevice {
    pub id: String,           // Platform-specific identifier
    pub name: String,         // Human-readable name
    pub device_type: DeviceType,
    pub is_default: bool,
}

#[derive(Debug, Clone, Copy, Serialize, Deserialize)]
pub enum DeviceType {
    Speakers,
    Headphones,
    Hdmi,
    Usb,
    Bluetooth,
    Unknown,
}

pub trait AudioDeviceManager {
    /// List all available output devices
    fn list_output_devices(&self) -> Vec<AudioDevice>;

    /// Get the current default output device
    fn get_default_output(&self) -> Option<AudioDevice>;

    /// Set the default output device
    fn set_default_output(&self, device_id: &str) -> Result<(), String>;

    /// List all available input devices
    fn list_input_devices(&self) -> Vec<AudioDevice>;

    /// Get the current default input device
    fn get_default_input(&self) -> Option<AudioDevice>;

    /// Set the default input device
    fn set_default_input(&self, device_id: &str) -> Result<(), String>;
}
