### macOS Implementation

```rust
// src/audio/macos.rs

use core_audio::audio_hardware::*;
use std::ffi::CStr;

pub struct MacOSAudioManager;

impl AudioDeviceManager for MacOSAudioManager {
    fn list_output_devices(&self) -> Vec<AudioDevice> {
        unsafe {
            let mut size: u32 = 0;
            let mut addr = AudioObjectPropertyAddress {
                mSelector: kAudioHardwarePropertyDevices,
                mScope: kAudioObjectPropertyScopeGlobal,
                mElement: kAudioObjectPropertyElementMain,
            };

            // Get size
            AudioObjectGetPropertyDataSize(
                kAudioObjectSystemObject,
                &addr,
                0,
                std::ptr::null(),
                &mut size,
            );

            let count = size as usize / std::mem::size_of::<AudioDeviceID>();
            let mut devices = vec![0u32; count];

            AudioObjectGetPropertyData(
                kAudioObjectSystemObject,
                &addr,
                0,
                std::ptr::null(),
                &mut size,
                devices.as_mut_ptr() as *mut _,
            );

            devices
                .into_iter()
                .filter_map(|id| self.device_info(id))
                .filter(|d| d.has_output())
                .collect()
        }
    }

    fn set_default_output(&self, device_id: &str) -> Result<(), String> {
        let id: AudioDeviceID = device_id.parse().map_err(|_| "Invalid device ID")?;

        unsafe {
            let addr = AudioObjectPropertyAddress {
                mSelector: kAudioHardwarePropertyDefaultOutputDevice,
                mScope: kAudioObjectPropertyScopeGlobal,
                mElement: kAudioObjectPropertyElementMain,
            };

            let result = AudioObjectSetPropertyData(
                kAudioObjectSystemObject,
                &addr,
                0,
                std::ptr::null(),
                std::mem::size_of::<AudioDeviceID>() as u32,
                &id as *const _ as *const _,
            );

            if result == 0 {
                Ok(())
            } else {
                Err(format!("Failed to set device: error {}", result))
            }
        }
    }
}
