### Linux Implementation (PipeWire/PulseAudio)

```rust
// src/audio/linux.rs

use std::process::Command;

pub struct LinuxAudioManager;

impl AudioDeviceManager for LinuxAudioManager {
    fn list_output_devices(&self) -> Vec<AudioDevice> {
        // Try PipeWire first, fall back to PulseAudio
        if Self::has_pipewire() {
            self.list_pipewire_sinks()
        } else {
            self.list_pulseaudio_sinks()
        }
    }

    fn set_default_output(&self, device_id: &str) -> Result<(), String> {
        let cmd = if Self::has_pipewire() {
            Command::new("wpctl")
                .args(["set-default", device_id])
                .output()
        } else {
            Command::new("pactl")
                .args(["set-default-sink", device_id])
                .output()
        };

        match cmd {
            Ok(output) if output.status.success() => Ok(()),
            Ok(output) => Err(String::from_utf8_lossy(&output.stderr).to_string()),
            Err(e) => Err(e.to_string()),
        }
    }
}

impl LinuxAudioManager {
    fn has_pipewire() -> bool {
        Command::new("wpctl").arg("--version").output().is_ok()
    }

    fn list_pipewire_sinks(&self) -> Vec<AudioDevice> {
        // wpctl status | parse sinks section
        let output = Command::new("wpctl")
            .args(["status"])
            .output()
            .ok()?;
        // Parse output...
    }

    fn list_pulseaudio_sinks(&self) -> Vec<AudioDevice> {
        // pactl list sinks short
        let output = Command::new("pactl")
            .args(["list", "sinks", "short"])
            .output()
            .ok()?;
        // Parse output...
    }
}
