### Windows Implementation

```rust
// src/audio/windows.rs

use windows::Win32::Media::Audio::*;
use windows::Win32::Media::Audio::Endpoints::*;
use windows::Win32::System::Com::*;

pub struct WindowsAudioManager;

impl AudioDeviceManager for WindowsAudioManager {
    fn list_output_devices(&self) -> Vec<AudioDevice> {
        unsafe {
            CoInitializeEx(None, COINIT_MULTITHREADED).ok();

            let enumerator: IMMDeviceEnumerator =
                CoCreateInstance(&MMDeviceEnumerator, None, CLSCTX_ALL).ok()?;

            let collection = enumerator
                .EnumAudioEndpoints(eRender, DEVICE_STATE_ACTIVE)
                .ok()?;

            let count = collection.GetCount().ok()?;
            let mut devices = Vec::with_capacity(count as usize);

            for i in 0..count {
                if let Ok(device) = collection.Item(i) {
                    if let Some(info) = self.device_info(&device) {
                        devices.push(info);
                    }
                }
            }

            devices
        }
    }

    fn set_default_output(&self, device_id: &str) -> Result<(), String> {
        // Use IPolicyConfig (undocumented but widely used)
        // Or use PowerShell as fallback
        let script = format!(
            r#"
            $device = Get-AudioDevice -List | Where-Object {{ $_.ID -eq '{}' }}
            if ($device) {{ Set-AudioDevice -ID $device.ID }}
            "#,
            device_id
        );

        Command::new("powershell")
            .args(["-Command", &script])
            .output()
            .map_err(|e| e.to_string())?;

        Ok(())
    }
}
