### Daemon Integration

```rust
// In src/daemon.rs

impl Daemon {
    fn handle_long_press_rotate(&mut self, direction: i8) {
        // Only if we're in device switching mode (after long press detected)
        if !self.device_switching_mode {
            return;
        }

        let devices = self.audio_manager.list_output_devices();
        let current_idx = devices.iter()
            .position(|d| d.is_default)
            .unwrap_or(0);

        let new_idx = if direction > 0 {
            (current_idx + 1) % devices.len()
        } else {
            (current_idx + devices.len() - 1) % devices.len()
        };

        self.selected_device_idx = new_idx;

        // Update OSD to show selection
        if let Some(osd) = &mut self.osd {
            osd.show_device_picker(&devices, new_idx);
        }
    }

    fn handle_long_press_release(&mut self) {
        if self.device_switching_mode {
            // Confirm selection
            let devices = self.audio_manager.list_output_devices();
            if let Some(device) = devices.get(self.selected_device_idx) {
                match self.audio_manager.set_default_output(&device.id) {
                    Ok(()) => {
                        info!("Switched to: {}", device.name);
                        EventLog::log(EventType::DeviceSwitch {
                            device_name: device.name.clone(),
                        });
                    }
                    Err(e) => error!("Failed to switch device: {}", e),
                }
            }
            self.device_switching_mode = false;
        } else {
            // Normal long-press release = F15 up
            CurrentPlatform::send_key_up(Key::F15);
        }
    }
}
