### Mock HID Device for Testing

```rust
// src/hid/mock.rs

use super::*;
use std::collections::VecDeque;
use std::sync::{Arc, Mutex};

#[derive(Clone)]
pub struct MockHidDevice {
    events: Arc<Mutex<VecDeque<HidEvent>>>,
    battery_level: Arc<Mutex<u8>>,
    connected: Arc<Mutex<bool>>,
}

pub enum HidEvent {
    Rotation(i8),           // -127 to 127
    Button(bool),           // pressed/released
    Report(Vec<u8>),        // Raw report
}

impl MockHidDevice {
    pub fn new() -> Self {
        Self {
            events: Arc::new(Mutex::new(VecDeque::new())),
            battery_level: Arc::new(Mutex::new(75)),
            connected: Arc::new(Mutex::new(true)),
        }
    }

    /// Queue a rotation event
    pub fn queue_rotation(&self, direction: i8) {
        let mut events = self.events.lock().unwrap();
        events.push_back(HidEvent::Rotation(direction));
    }

    /// Queue a button press/release
    pub fn queue_button(&self, pressed: bool) {
        let mut events = self.events.lock().unwrap();
        events.push_back(HidEvent::Button(pressed));
    }

    /// Queue a complete click (down + up)
    pub fn queue_click(&self) {
        self.queue_button(true);
        self.queue_button(false);
    }

    /// Queue a double-click
    pub fn queue_double_click(&self) {
        self.queue_click();
        self.queue_click();
    }

    /// Queue a triple-click
    pub fn queue_triple_click(&self) {
        self.queue_click();
        self.queue_click();
        self.queue_click();
    }

    /// Queue a long press (button down, no release)
    pub fn queue_long_press_start(&self) {
        self.queue_button(true);
    }

    /// Queue long press release
    pub fn queue_long_press_end(&self) {
        self.queue_button(false);
    }

    /// Set simulated battery level
    pub fn set_battery(&self, level: u8) {
        *self.battery_level.lock().unwrap() = level.min(100);
    }

    /// Simulate disconnect
    pub fn disconnect(&self) {
        *self.connected.lock().unwrap() = false;
    }

    /// Simulate reconnect
    pub fn reconnect(&self) {
        *self.connected.lock().unwrap() = true;
    }
}

impl HidDeviceTrait for MockHidDevice {
    fn read_timeout(&self, buf: &mut [u8], timeout: Duration) -> Result<usize, HidError> {
        if !*self.connected.lock().unwrap() {
            return Err(HidError::Disconnected);
        }

        let mut events = self.events.lock().unwrap();

        if let Some(event) = events.pop_front() {
            // Format: [report_id, button_state, rotation]
            buf[0] = 0x01; // Report ID

            match event {
                HidEvent::Rotation(dir) => {
                    buf[1] = 0x00; // No button
                    buf[2] = dir as u8;
                    Ok(3)
                }
                HidEvent::Button(pressed) => {
                    buf[1] = if pressed { 0x01 } else { 0x00 };
                    buf[2] = 0x00; // No rotation
                    Ok(3)
                }
                HidEvent::Report(data) => {
                    let len = data.len().min(buf.len());
                    buf[..len].copy_from_slice(&data[..len]);
                    Ok(len)
                }
            }
        } else {
            // Simulate timeout - no data
            std::thread::sleep(timeout.min(Duration::from_millis(10)));
            Err(HidError::Timeout)
        }
    }

    fn write(&self, _data: &[u8]) -> Result<usize, HidError> {
        Ok(0)
    }

    fn get_feature_report(&self, buf: &mut [u8]) -> Result<usize, HidError> {
        // Return battery level in feature report
        let level = *self.battery_level.lock().unwrap();
        buf[0] = 0x05; // Battery report ID
        buf[1] = level;
        buf[2] = 0x00; // Not charging
        Ok(3)
    }
}
```

### Virtual HID Device on Linux (uhid)

```rust
// src/hid/virtual_linux.rs

#[cfg(target_os = "linux")]
pub mod uhid {
    use std::fs::{File, OpenOptions};
    use std::io::{Read, Write};
    use std::os::unix::io::AsRawFd;

    const UHID_PATH: &str = "/dev/uhid";

    // UHID event types
    const UHID_CREATE2: u32 = 11;
    const UHID_INPUT2: u32 = 12;
    const UHID_DESTROY: u32 = 1;

    /// Surface Dial HID Report Descriptor
    const DIAL_REPORT_DESCRIPTOR: &[u8] = &[
        0x05, 0x01,        // Usage Page (Generic Desktop)
        0x09, 0x0E,        // Usage (System Multi-Axis Controller)
        0xA1, 0x01,        // Collection (Application)
        0x85, 0x01,        //   Report ID (1)
        0x05, 0x09,        //   Usage Page (Button)
        0x09, 0x01,        //   Usage (Button 1)
        0x15, 0x00,        //   Logical Minimum (0)
        0x25, 0x01,        //   Logical Maximum (1)
        0x75, 0x01,        //   Report Size (1)
        0x95, 0x01,        //   Report Count (1)
        0x81, 0x02,        //   Input (Data,Var,Abs)
        0x75, 0x07,        //   Report Size (7)
        0x81, 0x03,        //   Input (Const,Var,Abs)
        0x05, 0x01,        //   Usage Page (Generic Desktop)
        0x09, 0x37,        //   Usage (Dial)
        0x15, 0x81,        //   Logical Minimum (-127)
        0x25, 0x7F,        //   Logical Maximum (127)
        0x75, 0x08,        //   Report Size (8)
        0x95, 0x01,        //   Report Count (1)
        0x81, 0x06,        //   Input (Data,Var,Rel)
        0xC0,              // End Collection
    ];

    pub struct VirtualDial {
        uhid: File,
    }

    impl VirtualDial {
        pub fn new() -> std::io::Result<Self> {
            let uhid = OpenOptions::new()
                .read(true)
                .write(true)
                .open(UHID_PATH)?;

            let mut vdial = Self { uhid };
            vdial.create_device()?;
            Ok(vdial)
        }

        fn create_device(&mut self) -> std::io::Result<()> {
            // UHID_CREATE2 structure
            // This is simplified - real implementation needs proper struct packing
            let mut event = vec![0u8; 4308]; // Size of uhid_event

            // Event type
            event[0..4].copy_from_slice(&UHID_CREATE2.to_ne_bytes());

            // Name (128 bytes at offset 4)
            let name = b"Virtual Surface Dial";
            event[4..4+name.len()].copy_from_slice(name);

            // Vendor ID (2 bytes at offset 260)
            event[260..262].copy_from_slice(&0x045E_u16.to_le_bytes());

            // Product ID (2 bytes at offset 262)
            event[262..264].copy_from_slice(&0x091B_u16.to_le_bytes());

            // Report descriptor length (2 bytes at offset 268)
            let rd_len = DIAL_REPORT_DESCRIPTOR.len() as u16;
            event[268..270].copy_from_slice(&rd_len.to_le_bytes());

            // Report descriptor (at offset 270)
            event[270..270+DIAL_REPORT_DESCRIPTOR.len()].copy_from_slice(DIAL_REPORT_DESCRIPTOR);

            self.uhid.write_all(&event)?;
            Ok(())
        }

        pub fn send_rotation(&mut self, direction: i8) -> std::io::Result<()> {
            self.send_report(&[0x01, 0x00, direction as u8])
        }

        pub fn send_button(&mut self, pressed: bool) -> std::io::Result<()> {
            self.send_report(&[0x01, if pressed { 0x01 } else { 0x00 }, 0x00])
        }

        fn send_report(&mut self, data: &[u8]) -> std::io::Result<()> {
            let mut event = vec![0u8; 4308];

            // Event type: UHID_INPUT2
            event[0..4].copy_from_slice(&UHID_INPUT2.to_ne_bytes());

            // Data size (2 bytes at offset 4)
            event[4..6].copy_from_slice(&(data.len() as u16).to_le_bytes());

            // Data (at offset 6)
            event[6..6+data.len()].copy_from_slice(data);

            self.uhid.write_all(&event)?;
            Ok(())
        }
    }

    impl Drop for VirtualDial {
        fn drop(&mut self) {
            let mut event = vec![0u8; 4308];
            event[0..4].copy_from_slice(&UHID_DESTROY.to_ne_bytes());
            let _ = self.uhid.write_all(&event);
        }
    }
}
