    assert!(vol_25 < 50, "25% dial = {}% vol, should be < 50%", vol_25);

    // 50% dial should be between 60-80% volume
    let vol_50 = curve.apply(50);
    assert!(vol_50 > 60 && vol_50 < 80, "50% dial = {}% vol", vol_50);

    // 75% dial should be > 85% volume
    let vol_75 = curve.apply(75);
    assert!(vol_75 > 85, "75% dial = {}% vol, should be > 85%", vol_75);
}

#[test]
fn test_curve_inverse_roundtrip() {
    let curve = LogarithmicCurve::default();

    for dial_pos in (0..=100).step_by(5) {
        let volume = curve.apply(dial_pos);
        let recovered = curve.inverse(volume);

        // Should round-trip with at most 1% error
        assert!((dial_pos - recovered).abs() <= 1,
            "dial {} -> vol {} -> dial {}", dial_pos, volume, recovered);
    }
}
