### 2. Main Entry Point

```rust
// src/main.rs
use clap::{Parser, Subcommand};
use surface_dial::{Config, Daemon};

#[derive(Parser)]
#[command(name = "surface-dial")]
#[command(about = "Surface Dial Volume Controller")]
struct Cli {
    #[command(subcommand)]
    command: Option<Commands>,
}

#[derive(Subcommand)]
enum Commands {
    /// Start the daemon
    Daemon {
        #[command(subcommand)]
        action: DaemonAction,
    },
    /// Configuration commands
    Config {
        #[command(subcommand)]
        action: ConfigAction,
    },
    /// Show status
    Status {
        #[arg(long)]
        json: bool,
    },
}

fn main() {
    let cli = Cli::parse();

    // Initialize logging
    env_logger::Builder::from_env(
        env_logger::Env::default().default_filter_or("info")
    ).init();

    match cli.command {
        Some(Commands::Daemon { action }) => handle_daemon(action),
        Some(Commands::Config { action }) => handle_config(action),
        Some(Commands::Status { json }) => handle_status(json),
        None => {
            // Default: run daemon in foreground
            run_daemon_foreground();
        }
    }
}

fn run_daemon_foreground() {
    let config = Config::load();
    let mut daemon = Daemon::new(config);

    // Set up signal handling
    let running = daemon.running();
    ctrlc::set_handler(move || {
        running.store(false, std::sync::atomic::Ordering::SeqCst);
    }).expect("Failed to set Ctrl-C handler");

    daemon.run();
}
