### Daemon Integration

```rust
// In src/daemon.rs

impl Daemon {
    fn handle_rotation(&mut self, raw_rotation: i8) {
        // Apply sensitivity filtering
        let adjusted = match self.sensitivity.process(raw_rotation) {
            Some(v) => v,
            None => return,  // Within dead zone, ignore
        };

        // Rest of rotation handling with adjusted value
        let direction = adjusted.signum() as i8;
        let magnitude = adjusted.abs();

        // Apply to volume (may need to loop for large magnitude)
        for _ in 0..magnitude {
            self.apply_single_step(direction);
        }
    }

    fn handle_mode_change(&mut self) {
        // Reset dead zone accumulator on mode change
        self.sensitivity.reset();
    }
}
