// src/tray/macos.rs

use cocoa::appkit::{NSStatusBar, NSStatusItem, NSMenu, NSMenuItem};
use cocoa::base::{id, nil, YES, NO};
use objc::runtime::{Object, Sel};

pub struct MacOSTray {
    status_item: id,
    menu: id,
}

impl SystemTray for MacOSTray {
    fn new() -> Result<Self, TrayError> {
        unsafe {
            let status_bar = NSStatusBar::systemStatusBar(nil);
            let status_item = status_bar.statusItemWithLength_(-1.0);  // Variable width

            // Set initial icon
            let icon = Self::load_icon(TrayIcon::Connected)?;
            status_item.setImage_(icon);

            // Create menu
            let menu = NSMenu::new(nil);
            status_item.setMenu_(menu);

            Ok(Self { status_item, menu })
        }
    }

    fn set_icon(&mut self, icon: TrayIcon) {
        unsafe {
            let image = Self::load_icon(icon).unwrap();
            self.status_item.setImage_(image);
        }
    }

    fn set_tooltip(&mut self, text: &str) {
        unsafe {
            let ns_string = NSString::alloc(nil).init_str(text);
            self.status_item.setToolTip_(ns_string);
        }
    }

    fn set_menu(&mut self, menu: TrayMenu) {
        unsafe {
            // Clear existing menu
            self.menu.removeAllItems();

            for item in menu.items {
                match item {
                    MenuItem::Label { text } => {
                        let ns_item = NSMenuItem::alloc(nil)
                            .initWithTitle_action_keyEquivalent_(
                                NSString::alloc(nil).init_str(&text),
                                Sel::register(""),
                                NSString::alloc(nil).init_str(""),
                            );
                        ns_item.setEnabled_(NO);
                        self.menu.addItem_(ns_item);
                    }
                    MenuItem::Separator => {
                        self.menu.addItem_(NSMenuItem::separatorItem(nil));
                    }
                    MenuItem::Action { id, text, enabled, checked } => {
                        // Create action item with callback
                        // ... (delegate pattern for callbacks)
                    }
                    // ... handle other cases
                }
            }
        }
    }
}
