### Daemon Integration

```rust
// In src/daemon.rs

impl Daemon {
    fn update_tray(&mut self) {
        if let Some(tray) = &mut self.tray {
            // Update icon based on state
            let icon = if !self.device_connected {
                TrayIcon::Disconnected
            } else if self.is_muted() {
                TrayIcon::Muted
            } else if self.battery.map(|b| b.percent < 20).unwrap_or(false) {
                TrayIcon::LowBattery
            } else {
                TrayIcon::Connected
            };
            tray.set_icon(icon);

            // Update tooltip
            let tooltip = format!(
                "Surface Dial - {}%{}",
                self.current_volume,
                if self.is_muted() { " (Muted)" } else { "" }
            );
            tray.set_tooltip(&tooltip);

            // Update menu
            tray.set_menu(self.build_tray_menu());
        }
    }

    fn build_tray_menu(&self) -> TrayMenu {
        TrayMenu {
            items: vec![
                MenuItem::Label { text: "Surface Dial".into() },
                MenuItem::Separator,
                MenuItem::Label { text: format!("🔊 Volume: {}%", self.volume) },
                MenuItem::Label { text: format!("🎤 Mic: {}%", self.mic_volume) },
                MenuItem::Label { text: format!("🔋 Battery: {}%", 
                    self.battery.map(|b| b.percent.to_string()).unwrap_or("?".into())) },
                MenuItem::Separator,
                MenuItem::Action { 
                    id: "mode_volume".into(), 
                    text: "Volume Mode".into(), 
                    enabled: true,
                    checked: self.mode == ControlMode::Volume,
                },
                MenuItem::Action { 
                    id: "mode_mic".into(), 
                    text: "Microphone Mode".into(), 
                    enabled: true,
                    checked: self.mode == ControlMode::Microphone,
                },
                MenuItem::Separator,
                MenuItem::Action { id: "preferences".into(), text: "Preferences...".into(), enabled: true, checked: false },
                MenuItem::Action { id: "status".into(), text: "Show Status".into(), enabled: true, checked: false },
                MenuItem::Separator,
                MenuItem::Action { id: "quit".into(), text: "Quit".into(), enabled: true, checked: false },
            ],
        }
    }

    fn handle_tray_event(&mut self, event: TrayEvent) {
        match event {
            TrayEvent::MenuAction(id) => match id.as_str() {
                "mode_volume" => self.set_mode(ControlMode::Volume),
                "mode_mic" => self.set_mode(ControlMode::Microphone),
                "preferences" => self.open_preferences(),
                "status" => self.show_status(),
                "quit" => self.shutdown(),
                _ => {}
            },
            _ => {}
        }
    }
}
