### Foreground App Detection

```rust
// src/platform/foreground.rs

pub trait ForegroundAppDetector {
    fn get_foreground_app(&self) -> Option<AppInfo>;
}

#[derive(Debug, Clone)]
pub struct AppInfo {
    pub name: String,
    pub bundle_id: Option<String>,  // macOS
    pub process_id: Option<u32>,     // All platforms
    pub executable: Option<String>,  // Linux/Windows
}

#[cfg(target_os = "macos")]
impl ForegroundAppDetector for MacOSPlatform {
    fn get_foreground_app(&self) -> Option<AppInfo> {
        // Use NSWorkspace.frontmostApplication
        let output = Command::new("osascript")
            .args(["-e", r#"
                tell application "System Events"
                    set frontApp to first application process whose frontmost is true
                    return {name of frontApp, bundle identifier of frontApp}
                end tell
            "#])
            .output()
            .ok()?;

        // Parse output
        let parts: Vec<&str> = std::str::from_utf8(&output.stdout)
            .ok()?
            .trim()
            .split(", ")
            .collect();

        Some(AppInfo {
            name: parts.get(0)?.to_string(),
            bundle_id: parts.get(1).map(|s| s.to_string()),
            process_id: None,
            executable: None,
        })
    }
}

#[cfg(target_os = "linux")]
impl ForegroundAppDetector for LinuxPlatform {
    fn get_foreground_app(&self) -> Option<AppInfo> {
        // X11: Use _NET_ACTIVE_WINDOW property
        // Wayland: Compositor-specific (wlroots, GNOME, etc.)

        // X11 approach:
        let window_id = Command::new("xdotool")
            .args(["getactivewindow"])
            .output()
            .ok()?;

        let pid = Command::new("xdotool")
            .args(["getwindowpid", std::str::from_utf8(&window_id.stdout).ok()?.trim()])
            .output()
            .ok()?;

        let pid: u32 = std::str::from_utf8(&pid.stdout).ok()?.trim().parse().ok()?;

        // Get process name from /proc/pid/comm
        let name = std::fs::read_to_string(format!("/proc/{}/comm", pid)).ok()?;

        Some(AppInfo {
            name: name.trim().to_string(),
            bundle_id: None,
            process_id: Some(pid),
            executable: Some(name.trim().to_string()),
        })
    }
}

#[cfg(target_os = "windows")]
impl ForegroundAppDetector for WindowsPlatform {
    fn get_foreground_app(&self) -> Option<AppInfo> {
        use windows::Win32::UI::WindowsAndMessaging::*;
        use windows::Win32::Foundation::*;

        unsafe {
            let hwnd = GetForegroundWindow();
            let mut pid: u32 = 0;
            GetWindowThreadProcessId(hwnd, Some(&mut pid));

            // Get process name from handle
            let handle = OpenProcess(PROCESS_QUERY_LIMITED_INFORMATION, false, pid).ok()?;
            let mut buffer = [0u16; 260];
            let mut size = buffer.len() as u32;
            QueryFullProcessImageNameW(handle, PROCESS_NAME_WIN32, &mut buffer, &mut size).ok()?;

            let name = String::from_utf16_lossy(&buffer[..size as usize]);

            Some(AppInfo {
                name: std::path::Path::new(&name)
                    .file_stem()?
                    .to_string_lossy()
                    .to_string(),
                bundle_id: None,
                process_id: Some(pid),
                executable: Some(name),
            })
        }
    }
}
